-- Текст из книги «SRE: Коллективный разум» по урокам 1–4. Дополняет/заменяет короткие выжимки на полные фрагменты.

-- Урок 1 «Что такое SRE и зачем» — добавить чанки 5–6 (конец главы 1)
INSERT INTO lesson_content_chunks (lesson_id, chunk_index, body_text)
SELECT l.id, v.chunk_index, v.body_text
FROM lessons l
JOIN modules m ON m.id = l.module_id AND m.slug = 'foundations'
JOIN (VALUES
  (5, 'Роль SRE в российских компаниях. В большинстве российских компаний SRE — это улучшенный сисадмин. Типичная картина: компания переименовывает отдел эксплуатации, добавляет Kubernetes и объявляет, что у неё теперь SRE. Зрелые компании строят полноценные SRE-практики: SLO, error budgets, on-call, blameless postmortems. Проблемы рынка: дефицит кадров, размытость роли, культура постмортемов, санкционное давление. Российское SRE-сообщество активно развивается: курсы, конференции, Telegram-чаты. Должен ли SRE программировать? Консенсус: SRE должен уметь программировать с акцентом на управление ресурсами, отказоустойчивый код, наблюдаемость и возможность отката. YAML и HCL — не считаются; LeetCode для SRE — перебор. Модели распределения: выделенная SRE команда, embedded SRE, SRE чемпион из разработчиков, эволюционная модель. Главное правило: «Главное — не НЕ упасть. Главное — быстро локализовать и подняться.» Абсолютная надёжность невозможна и не нужна; нужен осознанный выбор уровня и культура быстрого восстановления.'),
  (6, 'SRE, DevOps и Platform Engineering — разные функции. DevOps оптимизирует доставку; SRE — надёжность и восстановление; Platform Engineering — самообслуживание и инфраструктура. Аналогия: DevOps — авиакомпания, SRE — служба безопасности полётов, Platform — аэропорт. На практике один человек может совмещать все три роли. Ключевое: SRE — это набор практик, не должность. Совет: не начинайте с найма «SRE-инженера», начните с практик — определите SLO для одного сервиса, настройте алертинг на burn rate, проведите первый blameless-постмортем.')
) AS v(chunk_index, body_text) ON true
WHERE l.title = 'Что такое SRE и зачем'
ON CONFLICT (lesson_id, chunk_index) DO UPDATE SET body_text = EXCLUDED.body_text;

-- Урок 2 «SRE, DevOps, Platform Engineering» — полный текст из главы 1 (таблица, авиация, роли)
INSERT INTO lesson_content_chunks (lesson_id, chunk_index, body_text)
SELECT l.id, v.chunk_index, v.body_text
FROM lessons l
JOIN modules m ON m.id = l.module_id AND m.slug = 'foundations'
JOIN (VALUES
  (1, 'DevOps, SRE и Platform Engineering — три аббревиатуры с разным фокусом. DevOps: культура и практики, слом стены между разработкой и эксплуатацией, фокус «как быстрее доставить», метрики Lead time и deployment frequency. SRE: инженерный подход к надёжности, фокус «как не уронить и быстро поднять», метрики SLO, error budget, MTTR. Platform Engineering: внутренние платформы и самообслуживание, метрики adoption rate и developer satisfaction. Аналогия с авиацией: DevOps — авиакомпания (расписание, оборот), SRE — служба безопасности полётов (расследование, чёрные ящики, правила), Platform — аэропорт (взлётные полосы, терминалы). Все три функции нужны; в одной компании один человек может совмещать роли, в другой — три команды. SRE — не должность, это набор практик.'),
  (2, 'Типичная картина в РФ: SRE как улучшенный сисадмин, переименование отдела без смены культуры. Зрелые компании строят SLO, error budgets, on-call, постмортемы. Проблемы: дефицит кадров, размытость роли («человек-оркестр»), формальные постмортемы, санкционное давление и импортозамещение. Сообщество развивается: курсы, DevOpsConf, SRE-митапы, Telegram-чаты. Должен ли SRE программировать? За код: без понимания архитектуры и кода нельзя улучшить надёжность. Против: можно выстроить процессы и надёжность без написания кода. Консенсус: управление ресурсами, отказоустойчивый код, наблюдаемость, возможность отката — ключевые навыки. Модели: выделенная SRE команда, embedded SRE, SRE чемпион, эволюционная (от пожарной команды к передаче дежурств в команды). «Главное — быстро локализовать и подняться.»'),
  (3, 'Абсолютная надёжность невозможна и не нужна. 100% доступности = нулевой бюджет на изменения; замершая система — мёртвая. Нужен осознанный выбор уровня надёжности, инструменты для его поддержания и культура быстрого восстановления. Не начинайте внедрение SRE с найма «SRE-инженера» — начните с практик: один критичный сервис, SLO, алертинг на burn rate, первый blameless-постмортем.')
) AS v(chunk_index, body_text) ON true
WHERE l.title = 'SRE, DevOps, Platform Engineering'
ON CONFLICT (lesson_id, chunk_index) DO UPDATE SET body_text = EXCLUDED.body_text;

-- Урок 3 «Как формулировать SLI» — глава 3 книги (типы SLI, формулы, HTTP, Kafka)
INSERT INTO lesson_content_chunks (lesson_id, chunk_index, body_text)
SELECT l.id, v.chunk_index, v.body_text
FROM lessons l
JOIN modules m ON m.id = l.module_id AND m.slug = 'sli-slo-sla'
JOIN (VALUES
  (1, 'Четыре типа индикаторов SLI. 1) Availability — доля успешных ответов; базовый SLI. 2) Latency — распределение времени ответа; страница, грузящаяся 30 секунд, технически доступна, но бесполезна. 3) Quality — корректность и полнота ответа (поиск не пустой, цены верные). 4) Freshness — актуальность данных (кэши, очереди, батч-обработка). Большинство начинает с availability + latency; quality добавляется позже. Формулы: одиночное SLI = good_requests / total_requests; для latency в Prometheus используйте histogram, не summary (summary не агрегируется между инстансами). Агрегирующее SLI: SUM(good_i * weight_i) / SUM(total_i * weight_i); веса задают критичность эндпоинтов. Композитное SLI — эндпоинты с разных сервисов; allOf = последовательная зависимость (надёжность перемножается), anyOf = параллельная.'),
  (2, 'Совмещение Availability и Latency в один SLI: каждый запрос — хороший или плохой. 500 → плохой; 200 → смотрим latency; 499 (client timeout) → только latency. Плюсы: одна цифра для бизнеса, предсказуемость. Минусы: произвольность весов. Совет: начните с совмещённого SLI, при необходимости добавьте раздельные для drill-down. HTTP-коды: 5xx — всегда плохо; 4xx — зависит (400 часто клиент; 429 при нормальной нагрузке — баг; 499 — только latency). Latency ошибочных запросов не учитывать — ошибки уже в error rate. SLI для Kafka: consumer lag с прогрессивной деградацией (clamp_max((lag/threshold - 1) * coeff, 1)). Quality SLI — для зрелых команд: доля запросов с непустым результатом, все обязательные блоки на странице.'),
  (3, 'Timeslice vs Event-based SLO. Timeslice: каждая минута хорошая/плохая, SLO = good_minutes/total_minutes; легко AND/OR для композитного SLO; потолок точности ~99.9975%. Event-based: каждый запрос отдельно; точнее, но сложнее; на высоком трафике burn rate очень быстрый. Рекомендация: начинайте с timeslice. Источники метрик: существующие метрики (быстрее всего), SLO-библиотеки при разнородном стеке, OpenTelemetry spans для CUJ. Где измерять: на сервисе (whitebox) — видим код, не видим инфру; на балансировщике (blackbox) — пользовательский опыт. Решение: комбинация. Проблема низкочастотных эндпоинтов: одна ошибка ночью даёт 93% vs 99.99% на высоком трафике. Решения: исключение ночных часов, traffic floor (denominator = max(actual, 1000)), порог шума, синтетический трафик. Совет: traffic floor — наиболее практично.')
) AS v(chunk_index, body_text) ON true
WHERE l.title = 'Как формулировать SLI'
ON CONFLICT (lesson_id, chunk_index) DO UPDATE SET body_text = EXCLUDED.body_text;

-- Урок 4 «SLO и Error Budget Policy» — глава 2 книги (SLO/SLI/SLA, error budget, внедрение)
INSERT INTO lesson_content_chunks (lesson_id, chunk_index, body_text)
SELECT l.id, v.chunk_index, v.body_text
FROM lessons l
JOIN modules m ON m.id = l.module_id AND m.slug = 'sli-slo-sla'
JOIN (VALUES
  (1, 'SLA (Service Level Agreement) — внешнее обязательство перед клиентом, юридический документ с последствиями. SLO (Service Level Objective) — внутренняя цель команды, амбициознее SLA; нарушение не ведёт к штрафам, но ведёт к действиям. SLI (Service Level Indicator) — конкретная метрика (например доля запросов с кодом != 5xx и latency < 500ms за 30 дней). Аналогия: SLA — ограничение на знаке, SLO — спидометр, SLI — датчик. Зазор между SLA и SLO — страховка. SLO как инструмент принятия решений: error budget сгорел → стоп-кран на фичи; бюджет в порядке → можно рисковать; бюджет хронически не расходуется → SLO слишком мягкий. Без обратной связи SLO бесполезен. Тест: «Что мы делаем по-другому из-за этой цифры?» Если «ничего» — SLO не работает.'),
  (2, 'Три подхода к внедрению SLO. 1) На сервис — каждый микросервис, понятный владелец; минус: не видно пользовательский опыт целиком. 2) На операцию — SLO на endpoint''ы (например /api/orders/create 99.95%, /api/orders/list 99.5%); минус: количество SLO растёт. 3) На критический путь пользователя (CUJ) — SLO на весь сценарий; плюс: реальный опыт; минус: сложно. Эволюционный путь: месяцы 1–3 per-service SLO; 3–6 per-operation; 6–12 CUJ-based; год 1–2 композитные SLO; год 2+ проактивный анализ. Самая частая ошибка — попытка покрыть SLO все сервисы сразу. Сервисный vs продуктовый подход: сервисный — SLO на компонент, алерт владельцу; продуктовый — SLO на бизнес-сценарий; практическое решение — двухуровневая модель (сервисный для инженеров, продуктовый для бизнеса). Начинайте с сервисного.'),
  (3, 'Техническая vs бизнесовая надёжность. Техническая — error rate, latency, «отвечает ли сервер вовремя». Продуктовая — конверсия, «может ли пользователь купить». Смешение даёт шум: маркетинговая кампания меняет трафик — SLI просел при рабочей системе. «Одна лампочка для бизнеса» — желание одного индикатора; проблема в том, что одна лампочка не различает критичность. Компромисс: дашборд с 5–7 ключевыми сценариями или «дашборд зловредности» (какой сервис вносит наибольший вклад в ошибки). Как продать девятки бизнесу: посчитать стоимость минуты простоя, перевести 99% vs 99.9% в минуты (7.3 ч vs 43 мин/месяц), показать цифры, дать бизнесу решить. MTTx vs SLO: MTTR/MTTF — дисперсия велика; SLO за период даёт чёткий бюджет. MTTR полезен для разбора инцидентов; дополнительно — MTTRC (time to root cause), ROCOF (частота сбоев).')
) AS v(chunk_index, body_text) ON true
WHERE l.title = 'SLO и Error Budget Policy'
ON CONFLICT (lesson_id, chunk_index) DO UPDATE SET body_text = EXCLUDED.body_text;
